4	/**
5	 * Computes the next generation of live cells per Conway's Game of Life rules.
6	 * Returns the set of cells alive after one tick.
7	 */
8	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
9	  const key = (x: number, y: number): string => `${x},${y}`;
10	  const live = new Set(liveCells.map(([x, y]) => key(x, y)));
11	  const neighborCounts = new Map<string, number>();
12	  for (const [x, y] of liveCells) {
13	    for (let dx = -1; dx <= 1; dx++) {
14	      for (let dy = -1; dy <= 1; dy++) {
15	        if (dx === 0 && dy === 0) continue;
16	        const k = key(x + dx, y + dy);
17	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
18	      }
19	    }
20	  }
21	  const next: Cell[] = [];
22	  for (const [k, count] of neighborCounts) {
23	    const [xs, ys] = k.split(",");
24	    const cell: Cell = [Number(xs), Number(ys)];
25	    if (live.has(k)) {
26	      if (count === 2 || count === 3) next.push(cell);
27	    } else {
28	      if (count === 3) next.push(cell);
29	    }
30	  }
31	  return next;
32	};
