export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const key = ([x, y]: Cell): string => `${x},${y}`;
  const live = new Set(liveCells.map(key));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = key(neighbor);
        const entry = neighborCounts.get(k) ?? { cell: neighbor, count: 0 };
        entry.count++;
        neighborCounts.set(k, entry);
      }
    }
  }
  const survivesOrIsBorn = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && live.has(k));
  const nextCells: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survivesOrIsBorn(k, count)) nextCells.push(cell);
  }
  return nextCells;
};
